import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Resources",
  subtitle: "Documentation, guides, and tools to help you get the most out of CyberVault.",
  sections: [
    {
      title: "Documentation",
      description: "Comprehensive guides for implementing and using CyberVault.",
      gridClass: "info-grid-3",
      grid: [
        {
          title: "Getting Started",
          description: "Quick start guide to get your account up and running in minutes.",
          cta: { text: "Read Docs →", link: "/docs/getting-started" }
        },
        {
          title: "Installation Guide",
          description: "Step-by-step installation for agents and connectors.",
          cta: { text: "Read Docs →", link: "/docs/installation" }
        },
        {
          title: "Configuration",
          description: "Advanced configuration options for your security setup.",
          cta: { text: "Read Docs →", link: "/docs/configuration" }
        },
        {
          title: "API Reference",
          description: "Complete API documentation with examples.",
          cta: { text: "View API →", link: "/api-reference" }
        },
        {
          title: "Integrations",
          description: "Connect CyberVault with 500+ security tools.",
          cta: { text: "View Integrations →", link: "/docs/integrations" }
        },
        {
          title: "Troubleshooting",
          description: "Solutions to common issues and error messages.",
          cta: { text: "Get Help →", link: "/docs/troubleshooting" }
        }
      ]
    },
    {
      title: "Learning Center",
      description: "Courses and tutorials to enhance your security knowledge.",
      bgColor: "#f8fafc",
      gridClass: "info-grid-2",
      grid: [
        {
          title: "Security Fundamentals",
          description: "Learn the basics of enterprise cybersecurity and threat detection."
        },
        {
          title: "Zero-Trust Mastery",
          description: "Complete guide to implementing zero-trust architecture."
        },
        {
          title: "Compliance Essentials",
          description: "Understanding SOC 2, ISO 27001, and other compliance frameworks."
        },
        {
          title: "AI in Security",
          description: "How machine learning is transforming threat detection."
        }
      ]
    },
    {
      title: "Tools & Utilities",
      description: "Free security tools to help you assess and improve your security posture.",
      gridClass: "info-grid-3",
      grid: [
        {
          title: "Security Score Checker",
          description: "Free tool to check your organization's security score."
        },
        {
          title: "Password Strength Tester",
          description: "Check if your passwords are secure enough."
        },
        {
          title: "Domain Scanner",
          description: "Scan your domain for common security issues."
        }
      ]
    },
    {
      title: "Status Page",
      description: "Real-time system status and incident history.",
      content: "<div class='status-indicator'><span class='status-dot online'></span> All Systems Operational</div><p>Last updated: Just now</p><p><a href='/status'>View Detailed Status →</a></p>"
    }
  ],
  color: "#6366f1"
};

function Resources() {
  return <InfoPageLayout {...pageData} />;
}

export default Resources;
